print('Path check:')
for p in paths:
    print(('OK  ' if Path(p).exists() else 'MISS') + p)
print('\nSelected symbol hits:')
for file in ['src/domain/settings.rs','src/services/overview.rs','src/workers/events.rs','src/main.rs','ui/main.slint','ui/scanner_tab.slint','src/platform/filesystem.rs','src/domain/overview.rs','src/domain/mod_manager.rs','src/platform/desktop.rs','src/platform/clipboard.rs']:
