fn ba2_suffixes(ini_files: &Fallout4IniFiles) -> Vec<String> {
    let language = ini_value(&ini_files.custom, "general", "slanguage")
        .or_else(|| ini_value(&ini_files.fallout4, "general", "slanguage"))
        .unwrap_or("en")
        .trim()
        .to_ascii_lowercase();
    let mut suffixes = vec![
